arguments.keystrokes:
awk -F'\t' '
$2 != "/var/data" && $2 != "/var/data/logs" && $2 != "/var/data/backups" && $2 != "/var/data/cache" && $2 != "/var/data/cache/thumbnails" && $2 != "/var/data/uploads" && $2 != "/var/data/archives" {
  file = $2
  sub(/.*\//, "", file)
  if (file ~ /\./) {
    ext = file
    sub(/.*\./, "", ext)
    ext = tolower(ext)
  } else {
    ext = "NO_EXTENSION"
  }
  sum[ext] += $1
}
END {
  print "extension,total_bytes"
  for (e in sum) print e","sum[e]
}' /home/user/disk_inventory.txt | (read header; echo "$header"; sort -t',' -k2,2rn) > /home/user/reports/extension_summary.csv

awk -F'\t' '
BEGIN { total = 0 }
$2 ~ /^\/var\/data\/[^\/]+\// || ($2 ~ /^\/var\/data\/[^\/]+$/ && $1 != 4096) {
  path = $2
  sub(/^\/var\/data\//, "", path)
  sub(/\/.*/, "", path)
  sum[path] += $1
  total += $1
}
END {
  for (d in sum) {
    pct = (sum[d] / total) * 100
    printf "%s %d %.1f%%\n", d, sum[d], pct
  }
}' /home/user/disk_inventory.txt | sort -t' ' -k2,2rn > /home/user/reports/directory_rollup.txt
